/* CanUserMgmtMapper.updateCanUser */
UPDATE CMN_USR_MST@DL_CAN
SET    USG_STRT_DT = #{usgStrtDt}
	  ,USG_END_DT = #{usgEndDt}
	  ,REASON = #{reason}
	  ,RVISN_ID = #{sessionUserId}
	  ,RVISN_DTTM = SYSDATE
WHERE  USR_ID = UPPER(#{usrId})

