  , SYSDATE
)

/* CanUserMgmtMapper.usrGrpAsgnHstInsert */ 
INSERT INTO CMN_USG_GRP_ASGN_HST@DL_CAN
(
	USR_ID
  , GRP_ID
  , REGST_ID
  , REGST_DTTM
  , SEQ_NUM
  , OPER_TPYE
)
VALUES
( 
	#{usrId}
  , #{grpId}
  , #{sessionUserId}
  , SYSDATE
  , (SELECT NVL(MAX(TO_NUMBER(SEQ_NUM)) + 1, 1) FROM CMN_USG_GRP_ASGN_HST WHERE USR_ID = #{usrId})
  , #{operType}
)

